import{_ as n,C as r,o as i,c as o,a3 as u,E as p,w as s,j as l,a}from"./chunks/framework.CH_GxKL1.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{"prev":{"text":"ch01 - 理解焦虑","link":"/readings/Taming_Your_Amygdala/contexts/Chapter 01 - 理解焦虑"},"next":{"text":"ch03 - 目标设定:夺回生活第一步","link":"/readings/Taming_Your_Amygdala/contexts/Chapter 03 - 目标设定：夺回生活的第一步"}},"headers":[],"relativePath":"readings/Taming_Your_Amygdala/contexts/Chapter 02 - 认识你的杏仁核.md","filePath":"readings/Taming_Your_Amygdala/contexts/Chapter 02 - 认识你的杏仁核.md","lastUpdated":1781795572000}'),d={name:"readings/Taming_Your_Amygdala/contexts/Chapter 02 - 认识你的杏仁核.md"};function h(_,e,c,m,g,x){const t=r("SplitNoteInsert");return i(),o("div",null,[e[1]||(e[1]=u('<h2 id="title" tabindex="-1">认识你的杏仁核 <a class="header-anchor" href="#title" aria-label="Permalink to &quot;认识你的杏仁核 {#title}&quot;">​</a></h2><p>大脑中发送信号产生焦虑的那个部分，小到可以放在你的手掌心里。 杏仁核的大小和形状大致像一颗杏仁。 事实上，&quot;amygdala&quot;这个词（发音为&quot;uh-MIG-da-la&quot;）来自希腊语中表示杏仁的单词。 你实际上有两个杏仁核，大脑的每一侧各有一个。 然而，传统上习惯用单数形式来指代这个成对的结构，因此在这本书中，我将讨论&quot;那个杏仁核&quot;（the amygdala）。</p><p>如果你想向别人展示你的杏仁核在哪里，你可以用你的食指来指出。 只需用你的右手食指指向你的右耳，左手食指指向你的右眼。 这两根手指连线交汇的位置，大约就是你右侧杏仁核在大脑中所处的位置。 （你也可以做镜像的动作来指出左侧杏仁核。） 杏仁核位于大脑深处，与同样位于该区域的一些非常有影响力的大脑结构相连，比如脑干、下丘脑、海马体和腹侧纹状体，以及影响皮层的唤醒网络（LeDoux, 2015）。 这些脑区之间的相互连接使得杏仁核能够在几分之一秒内创造出你对恐惧的生理体验——改变你的情绪、思维、注意力焦点以及各种身体功能。</p><p>更重要的是，这些变化发生在你无法控制的情况下，且大多在你不自觉的情况下进行。 正因如此，我们常常将杏仁核描述为有能力&quot;劫持&quot;大脑，并掌控我们的思维和感受。 这也解释了为什么我们常常不理解自己的情绪反应，以及为什么有时感觉我们的情绪&quot;失控了&quot;。 你对杏仁核的所作所为没有太多控制力，不过如果你更多地了解它的功能，你可以学会一些影响它的方法（Pittman &amp; Karle, 2015）。</p><p>就其核心而言，杏仁核是你大脑中一个小而强大的部分，旨在帮助你探测、回避、防御和生存于危险之中。 （杏仁核实际上还做更多的事情，但我们将专注于这些功能，因为它们与杏仁核在产生焦虑中的作用有关。） 特别是，杏仁核负责启动一种预编程的防御反应（LeDoux, 2015），不仅在人类身上存在，在所有动物身上都存在。 当它在我们的身体中触发这种内置反应时，我们通常将整个反应称为恐惧，因为恐惧是我们正在体验的情绪状态。 但杏仁核造成的反应涉及我们身体中除恐惧情绪之外的许多其他过程，包括抑制胃部活动、增加流向四肢的血流量以及释放肾上腺素。 我们真正经历的是一种防御性动机状态，是一系列身体变化的集合，这些变化使我们准备好采取旨在保护我们的行动。</p><p>这种防御性动机状态就是产生焦虑的根源，焦虑与恐惧感非常相似。 当我们能够识别出明确且迫在眉睫的危险时，比如一只正在低吼的狗或一辆正朝过马路的人疾驰而来的汽车，我们用&quot;恐惧&quot;这个词来描述杏仁核所创造的情绪。 相比之下，当我们在没有明确危险存在的情况下感受到这种情绪状态，仅仅是有未来威胁或负面结果的可能性时——例如，当我们在担心即将到来的考试或害怕第一次约会中尴尬的对话时——我们称这种情绪为焦虑。 无论你是感到恐惧、焦虑、畏惧还是类似的情绪，你的身体都处于杏仁核产生的防御状态，这种状态也被称为&quot;战斗或逃跑反应&quot;。</p><p>这种预编程的防御反应存在一个问题：它在设计上要保护你免受的那些危险，在世界大部分地区已经被成功消除了。 例如，你在日常生活中大概不会面临被捕食者吃掉的风险。 但你的杏仁核仍然在警惕着这类危险。 因此，当今世界的压力源——比如难以支付房贷或可能与老板发生争执——仍然会引发来自杏仁核的防御反应，这种反应旨在帮助你对抗或逃离威胁。 这就是为什么你的心率会加快、肌肉会紧张。 这些反应通常没有帮助，因为它们不适合当前的情境。 你不能逃离你的房贷，而打你的老板也不是明智之举。 防御反应可能在偶尔遇到真正的物理危险时帮助我们逃脱，但它在大多数你面临的情境中并不能提供优势。</p><p>你会逐渐认识到，你的杏仁核常常基于不正确或不充分的信息来制造防御反应（包括恐惧或焦虑感）。 一种看法是，杏仁核出发点是好的，但常常产生不必要的焦虑，并把我们也拖下水。 而这段旅程并不愉快！ 然而，你可以学习如何对这个对你的生活有如此重要影响的小小脑区获得更多的控制。</p><h3 id="每个人的杏仁核都一样吗" tabindex="-1">每个人的杏仁核都一样吗？ <a class="header-anchor" href="#每个人的杏仁核都一样吗" aria-label="Permalink to &quot;每个人的杏仁核都一样吗？&quot;">​</a></h3><p>既然你对杏仁核及其影响有了更多了解，你可能会想，不同的人是否有相同类型的杏仁核？ 是否有些人的杏仁核反应更强烈或更频繁，导致它比普通人的杏仁核产生更多的焦虑和恐惧？ 答案是肯定的：我们已经发现，有些人——甚至某些马、狗和老鼠——拥有更可能产生恐惧或焦虑的杏仁核。 例如，患有焦虑障碍的儿童与没有焦虑障碍的儿童相比，其杏仁核已被证明表现出差异（Milham et al., 2005）。 这些焦虑上的差异常常在儿童出生后的最初几个月就变得明显，那时我们会注意到有些婴儿更容易受惊或害怕。</p><p>研究表明，这些差异部分是由遗传影响造成的，这意味着焦虑方面的困难往往在家族中遗传（Hariri et al., 2005; Havinga, 2020）。 因此，如果你在与焦虑作斗争，你的其他家庭成员很可能也遭受焦虑困扰，尽管可能以不同的方式。 然而，正如你将在第9章和第10章中学到的，杏仁核能够学会以不同的方式回应，所以你与生俱来的杏仁核并不一定要决定你的命运。 例如，许多害羞和焦虑的孩子长大后成为有效的公众演说家和表演者。</p><p>但遗传并不是人们焦虑的唯一原因。 许多在早年生活中看起来并不焦虑的人，后来也会发展出焦虑困难。 杏仁核能够学会的事实也意味着，有些人的杏仁核学会在比以前更多的情境中产生焦虑。 杏仁核从我们特定的生活经验中学习，它对那些曾经与负面事件相关联的物体、情境和事件作出反应。 例如，如果你遭遇了车祸，你可能开始在乘车时感到焦虑。 突然间，焦虑在你生活中比之前更加限制了。</p><p>当事件非常具有威胁性并被认为是创伤性的时，杏仁核可能受到更严重的影响。 在一次创伤性生活经历之后，杏仁核中会发生一些变化，导致它总体上产生更多的焦虑，而不仅仅是在与创伤相关的情境中（Cacciaglia et al., 2017）。 但即使你的杏仁核可能已经学会了产生更多焦虑或在对以前从未反应过的情境中产生焦虑，如果给它适当类型的&quot;课程&quot;，它也可以再次学会以不同的方式回应。 虽然你无法完全控制你继承的大脑或你遇到的每一次生活经历，但你可以专注于增加你驯服杏仁核的资源。 你应该成为掌控自己生活的人，而不是你的杏仁核。</p><h3 id="如何对我的杏仁核施加更多影响" tabindex="-1">如何对我的杏仁核施加更多影响？ <a class="header-anchor" href="#如何对我的杏仁核施加更多影响" aria-label="Permalink to &quot;如何对我的杏仁核施加更多影响？&quot;">​</a></h3><p>你可以通过两种关键方式来影响你的杏仁核。 首先，你可以通过针对你日常生活中那些已被研究证明会影响杏仁核反应的方面，来改变杏仁核的总体反应水平。 换句话说，你可以通过以一种让杏仁核总体上更平静的方式来生活，从而驯服你的杏仁核。 其次，你可以通过向杏仁核提供关于特定情境的新信息，来教它在这些情境中做出不同的反应，这种方法称为暴露疗法。 大多数人发现，教杏仁核是更具挑战性的，因为它需要将杏仁核（和你自己）暴露在通常会引发焦虑的情境中。 将这两种方法——让杏仁核平静下来和教杏仁核——结合起来，是驯服它的最有效方式。</p><p>第一种方法，即改变你日常例行习惯中的一些习惯，可能是开始驯服杏仁核的最佳起点。 事实上，我要告诉你一些非常有用的信息，这些信息是在大约最近15年才被发现的：杏仁核的功能受一些日常习惯的影响，你可以以极低的成本改变这些习惯，并且这些改变能为杏仁核带来令人惊讶的平静效果。 这些习惯包括你的睡眠、运动和饮食。 当你首先从改变这些习惯开始时，你会发现第二步——教杏仁核做出不同的反应——会变得更容易，因为你在与一个更平静的杏仁核打交道。</p><p>在本书的后面部分，我将更详细地引导你完成这两个步骤。 然而，在你开始改变杏仁核这个充满挑战的过程之前，确保你有足够的动力并为前面的工作做好充分准备是很重要的。 因此，下一章将聚焦于你的人生目标。 通常，人们想要驯服杏仁核的原因，是因为他们感觉焦虑正在阻止他们过上想要的生活。 关键是要澄清你希望在人生中达成什么，这样你才能确定焦虑可能如何干扰这些目标——以及最终，你如何克服焦虑来实现你的目标。</p>',17)),p(t,{target:"title"},{default:s(()=>[...e[0]||(e[0]=[l("h2",{id:"笔记",tabindex:"-1"},[a("笔记 "),l("a",{class:"header-anchor",href:"#笔记","aria-label":'Permalink to "笔记"'},"​")],-1),l("h3",{id:"关于-认识杏仁核",tabindex:"-1"},[a('关于"认识杏仁核"： '),l("a",{class:"header-anchor",href:"#关于-认识杏仁核","aria-label":'Permalink to "关于"认识杏仁核"："'},"​")],-1),l("ul",null,[l("li",null,[l("p",null,`杏仁核主要可以产生"'恐惧'的生理体验"，从而"改变你的情绪、思维、注意力焦点以及各种身体功能"。`)]),l("li",null,[l("p",null,[a("更重要的是，这是一种"),l("strong",null,"无意识、不可控的本能反应"),a('，它让我们"难以理解自己的情绪反应"。')])]),l("li",null,[l("p",null,[a('特别的是，"杏仁核负责启动一种预编程的防御反应" --- 这种反应是一个'),l("em",null,"系统性"),a("反应，它牵扯到人体各个器官、各种生化过程的反应与波动。")])]),l("li",null,[l("p",null,'"这种防御性动机状态就是产生焦虑的根源，焦虑与恐惧感非常相似。"')]),l("li",null,[l("p",null,'但就像"移情"一样，"杏仁核预编程的防御"的最大问题就是，他要防御的对象已经不存在了；而用这种错位的防御模式对抗新的风险，往往会起到反效果。')])],-1),l("h3",{id:"关于-每个人的杏仁核都一样吗",tabindex:"-1"},[a('关于"每个人的杏仁核都一样吗？"： '),l("a",{class:"header-anchor",href:"#关于-每个人的杏仁核都一样吗","aria-label":'Permalink to "关于"每个人的杏仁核都一样吗？"："'},"​")],-1),l("ul",null,[l("li",null,"每个人的杏仁核反应的激烈程度是不一样的，遗传，是很重要的一个因素。"),l("li",null,'但更重要的，"生活经历"也会重塑杏仁核的反应能力 --- 尤其是"创伤性时刻"，这回让杏仁核更加歇斯底里地试图保护我们自己。'),l("li",null,'我们很难直接改变杏仁核，但是可以通过"自我训练"获得更清晰的意识，不被本能绑架，并教给它不一样的反应回路。')],-1),l("h2",{id:"关于-如何对我的杏仁核施加更多影响",tabindex:"-1"},[a('关于"如何对我的杏仁核施加更多影响？"： '),l("a",{class:"header-anchor",href:"#关于-如何对我的杏仁核施加更多影响","aria-label":'Permalink to "关于"如何对我的杏仁核施加更多影响？"："'},"​")],-1),l("ul",null,[l("li",null,"第一种方法，养成更平静的生活习惯；"),l("li",null,'第二种方法，"暴露疗法"，强迫自己在面对焦虑源时，采取不一样的反应回路。')],-1),l("hr",null,null,-1),l("h2",{id:"评语",tabindex:"-1"},[a("评语 "),l("a",{class:"header-anchor",href:"#评语","aria-label":'Permalink to "评语"'},"​")],-1),l("p",null,[l("strong",null,"整体评价：三小节对应清晰，核心概念抓得准，比第一章笔记更紧凑。")],-1),l("p",null,"几点具体反馈：",-1),l("p",null,[l("strong",null,"做得好的地方：")],-1),l("ul",null,[l("li",null,"按照原文三个小节组织笔记，结构一目了然"),l("li",null,'"预编程的防御反应"和"系统性反应"这两个点提炼得很好——很多人只记"杏仁核产生恐惧"，你注意到了它是一个涉及多器官、多生化过程的全身反应'),l("li",null,'捕捉到了遗传 + 经历双重影响，没有陷入"天生如此"的宿命论'),l("li",null,"两种影响杏仁核的方法（生活习惯 + 暴露疗法）概括得简洁准确")],-1),l("p",null,[l("strong",null,"可以商榷/加强的地方：")],-1),l("ul",null,[l("li",null,'"移情"这个类比不太贴切。原文说的是防御反应是为原始威胁（捕食者）设计的，与当代压力（房贷、老板）不匹配——本质是"工具与场景错位"，不是"移情"（移情是把对过去某人的情感转移到当下他人身上）。换一个比喻会更准确'),l("li",null,'"歇斯底里"这个词建议换成更中性的表达，比如"过度警觉"或"反应过度"，避免不必要的联想'),l("li",null,"遗漏了杏仁核的解剖学定位（杏仁状、位于大脑深处、怎么用手指比划位置），这对于具象化理解很有帮助——知道它在哪、长什么样，比抽象讨论更容易建立直觉"),l("li",null,[a("遗漏了原文中一个重要区分："),l("strong",null,"恐惧 vs 焦虑"),a("——有明确、迫在眉睫的危险时叫恐惧，没有明确危险、只是潜在未来威胁时叫焦虑。这个区分是整本书后续讨论的基础")]),l("li",null,'两种方法的描述可以稍微展开一句——"养成平静生活习惯"具体指什么？原文提到了睡眠、运动、饮食，可以顺手记下这三个关键词')],-1),l("p",null,[l("strong",null,"一句话总结：概念抓得准，结构好，补上几个被跳过的基础定义（恐惧/焦虑区分、杏仁核位置）就更扎实了。")],-1)])]),_:1})])}const b=n(d,[["render",h]]);export{f as __pageData,b as default};
